import android.app.Application;
import android.util.Log;

import androidx.annotation.NonNull;
import androidx.lifecycle.AndroidViewModel;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class UserViewModel extends AndroidViewModel {

    private MutableLiveData<User> userData = new MutableLiveData<>();
    private ApiClient apiClient;

    public UserViewModel(@NonNull Application application) {
        super(application);
        apiClient = ApiClient.getInstance();
    }

    public void getUserData() {
        Call<UsersResponse> call = apiClient.getRetrofit().create(ApiInterface.class).getUserList();
        call.enqueue(new Callback<UsersResponse>() {
            @Override
            public void onResponse(Call<UsersResponse> call, Response<UsersResponse> response) {
                if (response.isSuccessful()) {
                    UsersResponse usersResponse = response.body();
                    User user = usersResponse.getUser();
                    userData.setValue(user);
                } else {
                    Log.e("UserViewModel", "Error fetching user data: " + response.code());
                }
            }

            @Override
            public void onFailure(Call<UsersResponse> call, Throwable t) {
                Log.e("UserViewModel", "Error fetching user data: " + t.getMessage());
            }
        });
    }

    public LiveData<User> getUserDataLive() {
        return userData;
    }
}

public class ApiClient {

    private static final String PRODUCTION_BASE_URL = "https://api.example.com";
    private static final String STAGING_BASE_URL = "https://staging-api.example.com";
    private static final String DEVELOPMENT_BASE_URL = "http://localhost:8080";

    private static ApiClient instance;

    public static synchronized ApiClient getInstance() {
        if (instance == null) {
            instance = new ApiClient();
        }
        return instance;
    }

    public Retrofit getRetrofit() {
        switch (BuildConfig.BUILD_TYPE) {
            case "production":
                return new Retrofit.Builder()
                        .baseUrl(PRODUCTION_BASE_URL)
                        .addConverterFactory(GsonConverterFactory.create())
                        .build();
            case "staging":
                return new Retrofit.Builder()
                        .baseUrl(STAGING_BASE_URL)
                        .addConverterFactory(GsonConverterFactory.create())
                        .build();
            default:
                return new Retrofit.Builder()
                        .baseUrl(DEVELOPMENT_BASE_URL)
                        .addConverterFactory(GsonConverterFactory.create())
                        .build();
        }
    }
}

